    for (int i = 1; i <= c; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    auto find = [&](int x) -> int {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

