#include <vector>
#include <queue>
#include <unordered_map>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<int> parent(c + 1, 0);
    vector<int> rank(c + 1, 0);
    for (int i = 1; i <= c; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    auto find = [&](int x) -> int {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_ = [&](int x, int y) {
        int x_root = find(x);
        int y_root = find(y);
        if (x_root == y_root) return;
        if (rank[x_root] < rank[y_root]) {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if (rank[x_root] == rank[y_root]) {
                ++rank[x_root];
            }
        }
    };

    for (const auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        union_(u, v);
    }

    unordered_map<int, priority_queue<int>> component_pq;
    for (int i = 1; i <= c; ++i) {
        int root = find(i);
        if (component_pq.find(root) == component_pq.end()) {
            component_pq[root] = priority_queue<int>();
        }
        component_pq[root].push(-i);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& query : queries) {
        int type = query[0];
        int x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = find(x);
                priority_queue<int>& pq = component_pq[root];
                bool found = false;
                while (!pq.empty()) {
                    int top_neg = pq.top();
                    int top_id = -top_neg;
                    if (online[top_id]) {
                        result.push_back(top_id);
                        found = true;
                        break;
                    } else {
                        pq.pop();
                    }
                }
                if (!found) {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
